import random

def encrypt(plaintext):
    ciphertext = ""
    for char in plaintext:
        if char.isalpha():
            if char.isupper():
                ciphertext += chr((ord(char) - 65 + random.randint(1, 25)) % 26 + 65)
            else:
                ciphertext += chr((ord(char) - 97 + random.randint(1, 25)) % 26 + 97)
        else:
            ciphertext += char
    return ciphertext

def decrypt(ciphertext):
    plaintext = ""
    for char in ciphertext:
        if char.isalpha():
            if char.isupper():
                plaintext += chr((ord(char) - 65 - random.randint(1, 25)) % 26 + 65)
            else:
                plaintext += chr((ord(char) - 97 - random.randint(1, 25)) % 26 + 97)
        else:
            plaintext += char
    return plaintext
